window.HA_EVENTS = [
  { y:-3100, region:'westasia', sig:'civilization',
    t:{zh:'楔形文字 & 象形文字诞生', en:'Cuneiform & hieroglyphs emerge'},
    info:{zh:'两河流域的苏美尔人在泥板上刻下楔形符号，几乎同时尼罗河畔的古埃及人将象形文字凿入石壁。文字让人类第一次将记忆从口耳相传中解放出来——历史，从此可以被书写。',
          en:'Sumerians pressed wedge-shaped marks into clay while Egyptians carved hieroglyphs into stone. For the first time, memory could outlive the speaker — history became writable.'} },
  { y:-2700, region:'eastasia', sig:'china',
    t:{zh:'传说中的黄帝时代', en:'Legendary era of the Yellow Emperor'},
    info:{zh:'按古史传说，轩辕黄帝在涿鹿之战击败蚩尤、统合华夏部族，被尊为中华民族的人文始祖。考古上对应仰韶文化晚期与龙山文化前夜——中华文明的种子正在黄河两岸萌发。',
          en:'Tradition places the Yellow Emperor here — victor at Zhuolu and patriarch of Huaxia. Archaeologically, late Yangshao and proto-Longshan cultures were taking root along the Yellow River.'} },
  { y:-2500, region:'africa', sig:'monument',
    t:{zh:'吉萨大金字塔落成', en:'Great Pyramid of Giza'},
    info:{zh:'胡夫法老的陵墓由约 230 万块巨石垒成，高 146.6 米，三千八百年间一直是地球上最高的人造建筑。它既是死后世界的入口，也是古王国权力与几何学的极限宣言。',
          en:'Khufu\'s tomb — 2.3 million stones, 146.6 m tall, the tallest man-made structure on Earth for 3,800 years. A doorway to the afterlife and a manifesto of Old Kingdom geometry.'} },
  { y:-2070, region:'eastasia', sig:'china',
    t:{zh:'夏朝建立 · 中国第一个王朝', en:'Xia Dynasty founded'},
    info:{zh:'相传大禹治水有功而受禅，开启"家天下"。二里头遗址的青铜爵、宫殿基址将传说推入考古的实证。从此中国进入有"朝代"的时间。',
          en:'Yu the Great, hero of flood-taming, founded a hereditary line — the first Chinese dynasty. The Erlitou site\'s bronze vessels and palace foundations turn legend into archaeology.'} },
  { y:-1600, region:'eastasia', sig:'china',
    t:{zh:'商汤灭夏 · 商朝建立', en:'Shang dynasty replaces Xia'},
    info:{zh:'商汤起兵于亳，鸣条之战覆夏。商人精于青铜与卜辞，殷墟甲骨成为汉字最早的成熟形态——三千年中文血脉，自此清晰。',
          en:'Tang of Shang overthrew Xia at Mingtiao. Masters of bronze and oracle bones, the Shang gave China the earliest mature form of its script — the bloodline of three millennia.'} },
  { y:-1200, region:'westasia', sig:'collapse',
    t:{zh:'青铜时代大崩溃', en:'Bronze Age Collapse'},
    info:{zh:'地中海东岸在数十年间陷入连锁崩坏:迈锡尼、赫梯、乌加里特、新王国埃及——一个个青铜文明在"海上民族"、地震、干旱与贸易网断裂中相继瓦解，黑暗时代降临。',
          en:'Within decades, Mycenae, the Hittites, Ugarit and New-Kingdom Egypt all collapsed under "Sea Peoples", quakes, drought and broken trade. A dark age fell across the eastern Mediterranean.'} },
  { y:-1046, region:'eastasia', sig:'china',
    t:{zh:'武王伐纣 · 周代商', en:'Zhou conquers Shang at Muye'},
    info:{zh:'牧野之战，周武王以"天命"为号召击溃殷商。周公制礼作乐，分封诸侯——"天命""礼乐""华夷"等观念奠定中华政治文化两千年的底色。',
          en:'At Muye, King Wu of Zhou invoked the "Mandate of Heaven" to topple the Shang. The Duke of Zhou\'s rites and feudal grants framed Chinese political thought for two millennia.'} },
  { y:-776, region:'europe', sig:'culture',
    t:{zh:'第一届古代奥运会', en:'First Ancient Olympic Games'},
    info:{zh:'希腊各邦以宗教节庆之名暂止战火，会聚奥林匹亚竞技。城邦文化、共同语言与共享神祇——古希腊作为一个"文化体"在此成形。',
          en:'Greek poleis paused their wars to compete at Olympia in honor of Zeus. Shared games, language and gods — this is when "Greek civilization" cohered as a cultural body.'} },
  { y:-551, region:'eastasia', sig:'china',
    t:{zh:'孔子诞生于鲁', en:'Confucius is born in Lu'},
    info:{zh:'仲尼生于乱世，周游列国十四年。"仁""礼""君子"——他塑造了东亚两千五百年的伦理语法。汉以后，孔子之道成为帝国的官方哲学。',
          en:'Born into chaos, Kong Qiu wandered the warring states for 14 years. His grammar of ren (humaneness), li (rites) and the junzi shaped East Asian ethics for 2,500 years.'} },
  { y:-500, region:'global', sig:'axial',
    t:{zh:'轴心时代:孔子·佛陀·苏格拉底', en:'Axial Age: Confucius · Buddha · Socrates'},
    info:{zh:'公元前 6 至 4 世纪，中国（孔子、老子）、印度（佛陀、耆那）、波斯（琐罗亚斯德）、希腊（苏格拉底、柏拉图）几乎同时诞生了对人之处境的根本性追问。雅斯贝尔斯称之为"轴心时代"——人类精神从此转身。',
          en:'In two centuries, China, India, Persia and Greece simultaneously birthed thinkers asking the deepest questions about being human. Karl Jaspers called it the Axial Age — the spiritual pivot of our species.'} },
  { y:-221, region:'eastasia', sig:'china',
    t:{zh:'秦始皇统一中国', en:'Qin Shi Huang unifies China'},
    info:{zh:'嬴政横扫六合，废分封、置郡县；书同文、车同轨、统一度量衡。两千年帝制由此定型，"中国"作为政治实体首次成形。',
          en:'Ying Zheng swept away the warring states, abolished feudalism, standardized script, axles and measures. The 2,000-year imperial template — and "China" as a political body — is forged here.'} },
  { y:-138, region:'eastasia', sig:'china',
    t:{zh:'张骞通西域 · 丝绸之路开启', en:'Zhang Qian opens the Silk Road'},
    info:{zh:'汉武帝遣张骞出使大月氏，"凿空"西域。此后驼铃自长安直抵罗马——丝绸、纸张、佛教、葡萄、苜蓿沿这条横贯欧亚的血管来回流动。',
          en:'Emperor Wu of Han sent Zhang Qian westward to seek allies. The road he opened carried silk to Rome and Buddhism to China — Eurasia\'s arterial vein for fifteen centuries.'} },
  { y:-27, region:'europe', sig:'empire',
    t:{zh:'屋大维称帝 · 罗马帝国建立', en:'Roman Empire founded under Augustus'},
    info:{zh:'屋大维终结百年内战，被元老院授予"奥古斯都"尊号。共和形骸犹存，权力归于一身。"罗马治下的和平"延续两个世纪——西方"帝国"的原型在此铸成。',
          en:'Octavian ended a century of civil war and was crowned Augustus. The Republic\'s shell remained; power did not. The Pax Romana would last two centuries — the prototype of "empire" in the West.'} },
  { y:33, region:'westasia', sig:'religion',
    t:{zh:'耶稣受难 · 基督教诞生', en:'Crucifixion of Jesus'},
    info:{zh:'罗马犹太行省的一名木匠在十字架上死去。他的门徒坚信他三日复活，将信息带向地中海。三百年后，这个边缘小教派将成为罗马帝国的国教，进而塑造整个西方文明。',
          en:'A carpenter died on a Roman cross in Judea. His disciples carried news of resurrection across the Mediterranean. Within three centuries this fringe sect would become the religion of Rome — and of the West.'} },
  { y:105, region:'eastasia', sig:'china',
    t:{zh:'蔡伦改进造纸术', en:'Cai Lun perfects papermaking'},
    info:{zh:'东汉宦官蔡伦总结民间经验，以树皮、麻头、破布、渔网为原料，制出便宜易得的"蔡侯纸"。一千年后，纸张经阿拉伯传入欧洲，知识的物理形态从此改变。',
          en:'The Han eunuch Cai Lun refined an existing craft, using bark and rags to make cheap paper. A millennium later it reached Europe via the Arab world — and the physical form of knowledge changed forever.'} },
  { y:476, region:'europe', sig:'collapse',
    t:{zh:'西罗马帝国灭亡', en:'Fall of the Western Roman Empire'},
    info:{zh:'日耳曼将领奥多亚塞废黜末代皇帝罗慕路斯·奥古斯都，西罗马的法律、税收与城市秩序随之蒸发。欧洲进入"中世纪"——长达千年的破碎与重组。',
          en:'The Germanic chieftain Odoacer deposed Romulus Augustulus. Roman law, taxes and urban life evaporated in the West, and Europe entered a thousand years of fragmentation called the Middle Ages.'} },
  { y:622, region:'westasia', sig:'religion',
    t:{zh:'希吉拉 · 伊斯兰纪元开始', en:'Hijra — Islamic era begins'},
    info:{zh:'穆罕默德率信徒自麦加迁往麦地那，在那里建立第一个穆斯林共同体。这一年成为伊斯兰历元年。一个世纪后，哈里发的旗帜将从西班牙飘到印度河。',
          en:'Muhammad and his followers migrated from Mecca to Medina, founding the first Muslim community. Within a century the Caliphate would stretch from Spain to the Indus.'} },
  { y:751, region:'eastasia', sig:'china',
    t:{zh:'怛罗斯之战 · 造纸术西传', en:'Battle of Talas — paper goes West'},
    info:{zh:'高仙芝率唐军远征中亚，败于阿拔斯军。被俘的唐朝纸匠把造纸术带到撒马尔罕、巴格达、最终到达欧洲。一场失败的边境战，成了文化史的分水岭。',
          en:'Tang general Gao Xianzhi was defeated deep in Central Asia. Among the captives were Chinese papermakers, whose craft soon reached Samarkand, Baghdad, and eventually Europe.'} },
  { y:1096, region:'europe', sig:'war',
    t:{zh:'十字军东征开始', en:'First Crusade'},
    info:{zh:'乌尔班二世在克莱蒙号召夺回圣地，骑士、农民、流亡者数十万东进。两个世纪的圣战重塑了基督教世界与伊斯兰世界的边界与彼此想象。',
          en:'Pope Urban II called for the Holy Land\'s recapture at Clermont. Knights, peasants and exiles marched east. Two centuries of holy war would reshape the borders — and the imagination — of Christendom and Islam.'} },
  { y:1206, region:'eastasia', sig:'empire',
    t:{zh:'成吉思汗建立蒙古帝国', en:'Genghis Khan founds the Mongol Empire'},
    info:{zh:'铁木真在斡难河源被诸部尊为"成吉思汗"。半个世纪内，蒙古铁骑从太平洋杀到多瑙河，建立人类史上版图最大的陆上帝国。欧亚第一次被一只手掌握。',
          en:'On the Onon River, Temüjin was proclaimed Genghis Khan. Within fifty years his horsemen reached the Danube — the largest contiguous empire in history. For the first time, Eurasia was held by a single hand.'} },
  { y:1271, region:'eastasia', sig:'china',
    t:{zh:'忽必烈建立元朝', en:'Kublai Khan founds the Yuan Dynasty'},
    info:{zh:'忽必烈定国号"大元"，定都大都（今北京）。八年后崖山之战南宋覆灭，中国第一次被异族完整统治。元的驿站系统将欧亚连成一张网，马可·波罗就是顺着它走来的。',
          en:'Kublai proclaimed the Yuan and built Khanbaliq (modern Beijing). After Yaishan in 1279, all of China lay under foreign rule for the first time. Marco Polo arrived along the Yuan post-road network.'} },
  { y:1347, region:'europe', sig:'plague',
    t:{zh:'黑死病横扫欧亚', en:'Black Death sweeps Eurasia'},
    info:{zh:'鼠疫沿丝绸之路与热那亚商船登陆西西里，四年内吞噬欧洲三分之一人口。劳力骤减、农奴制松动、教会权威动摇——一场瘟疫意外松开了中世纪的扣环。',
          en:'Plague arrived at Sicily on Genoese ships and killed a third of Europe in four years. Labor scarcity broke serfdom; the Church\'s authority cracked. A pandemic loosened the Middle Ages.'} },
  { y:1368, region:'eastasia', sig:'china',
    t:{zh:'朱元璋建立明朝', en:'Zhu Yuanzhang founds the Ming Dynasty'},
    info:{zh:'红巾军出身的朱元璋驱逐蒙元，定都南京，国号大明。明朝重塑科举与里甲，重建汉人王朝秩序，并在永乐年间将都城北迁，启动紫禁城与郑和下西洋的盛世。',
          en:'A former Red Turban rebel, Zhu drove out the Mongols and founded the Ming. The dynasty restored Han Chinese rule, the exam system, and — under Yongle — built the Forbidden City and launched Zheng He\'s voyages.'} },
  { y:1405, region:'eastasia', sig:'china',
    t:{zh:'郑和首次下西洋', en:'Zheng He\'s first voyage'},
    info:{zh:'郑和率两万七千人、二百余艘宝船从苏州刘家港启航。七下西洋远至东非，比哥伦布早八十七年。然而明帝国旋即转向内陆——大航海的接力棒被悄然交给了葡萄牙人。',
          en:'Zheng He sailed from Liujiagang with 27,000 men and 200 treasure ships, eventually reaching East Africa — 87 years before Columbus. Yet the Ming soon turned inward, handing the age of sail to the Portuguese.'} },
  { y:1440, region:'europe', sig:'tech',
    t:{zh:'古登堡发明活字印刷术', en:'Gutenberg\'s movable-type press'},
    info:{zh:'美因茨的金匠约翰内斯·古登堡造出金属活字与油墨印刷机。书籍从神职人员的特权变成市民的日用品。五十年后欧洲已有上千万册图书在流传——宗教改革、科学革命、启蒙运动皆生于此。',
          en:'A goldsmith in Mainz built a metal-type press with oil-based ink. Books fell from clerical privilege into common hands. Within fifty years tens of millions circulated — fueling Reformation, Science and Enlightenment.'} },
  { y:1453, region:'europe', sig:'collapse',
    t:{zh:'君士坦丁堡陷落 · 中世纪终', en:'Fall of Constantinople'},
    info:{zh:'奥斯曼苏丹穆罕默德二世以巨炮轰塌千年罗马城墙，拜占庭终结。希腊学者携古籍逃亡意大利，点燃文艺复兴；欧洲也被迫向西寻找通往东方的新航路。',
          en:'Sultan Mehmed II breached the millennial walls with massive cannon, ending Byzantium. Greek scholars fled to Italy with ancient texts, fueling the Renaissance — and pushing Europe to seek new sea-roads east.'} },
  { y:1492, region:'americas', sig:'discovery',
    t:{zh:'哥伦布抵达美洲', en:'Columbus reaches the Americas'},
    info:{zh:'热那亚水手哥伦布奉西班牙王室之命西航寻印度，却在加勒比海撞上一片"新世界"。"哥伦布大交换"由此开始——玉米、马铃薯、马匹、天花、白银，跨越大洋彻底重写了两个半球。',
          en:'Christopher Columbus landed in the Caribbean, mistaking it for India. The Columbian Exchange — maize, potatoes, horses, smallpox, silver — would rewrite both hemispheres.'} },
  { y:1517, region:'europe', sig:'religion',
    t:{zh:'马丁·路德 · 宗教改革', en:'Luther begins the Reformation'},
    info:{zh:'路德将《九十五条论纲》钉上维登堡教堂大门，质疑赎罪券与教皇权威。借助古登堡印刷机，火星迅速燎原。欧洲分裂为新旧两教，世俗王权趁势崛起。',
          en:'Luther nailed the 95 Theses to a Wittenberg church door, attacking indulgences and papal authority. Carried by Gutenberg\'s press, the spark became wildfire. Europe split — and secular monarchs rose.'} },
  { y:1644, region:'eastasia', sig:'china',
    t:{zh:'明亡清兴 · 满洲入关', en:'Qing replaces Ming — Manchus enter the pass'},
    info:{zh:'李自成攻陷北京，崇祯帝煤山自缢；吴三桂引清军入关，多尔衮一举入主紫禁城。中国由满洲人统治至 1912 年，疆域在乾隆朝达到帝制时代最广。',
          en:'Li Zicheng took Beijing; Emperor Chongzhen hanged himself on Coal Hill. Wu Sangui let the Qing through Shanhai Pass and Dorgon entered the Forbidden City. Manchu rule lasted until 1912.'} },
  { y:1687, region:'europe', sig:'science',
    t:{zh:'牛顿《自然哲学之数学原理》', en:'Newton\'s Principia'},
    info:{zh:'牛顿用三大定律和万有引力，将天体与苹果的运动统一进同一张数学表。宇宙是一台可计算的机器——这种世界观将主导接下来三个世纪。',
          en:'With three laws and universal gravitation, Newton folded planets and apples into a single equation. The universe became calculable — a worldview that would dominate three centuries.'} },
  { y:1776, region:'americas', sig:'revolution',
    t:{zh:'美国独立宣言', en:'US Declaration of Independence'},
    info:{zh:'十三个英属殖民地宣布"人人生而平等"，与英王决裂。它把启蒙运动的抽象原则写进了一份政治文件——人民有权重设政府。一场全球的"民主实验"自此开张。',
          en:'Thirteen British colonies proclaimed "all men are created equal" and broke with the king. Enlightenment ideals became a political document. A global experiment in self-government had begun.'} },
  { y:1789, region:'europe', sig:'revolution',
    t:{zh:'法国大革命爆发', en:'French Revolution'},
    info:{zh:'巴士底狱被攻破，旧制度崩塌。"自由、平等、博爱"从沙龙走上街头，王权、教会、贵族被一并审判。革命的余波——民族主义、共和、独裁——回响整个 19 世纪。',
          en:'The Bastille fell and the Ancien Régime collapsed. "Liberty, Equality, Fraternity" left the salons for the streets. Its aftershocks — nationalism, republicanism, dictatorship — defined the 19th century.'} },
  { y:1840, region:'eastasia', sig:'china',
    t:{zh:'鸦片战争 · 中国近代史开端', en:'First Opium War — China\'s modern era begins'},
    info:{zh:'英国为鸦片贸易对清宣战。坚船利炮轰开国门，《南京条约》割香港、开五口、赔银两千一百万。"天朝"自此跌入"百年屈辱"，也被迫开始追问:中国为何落后？',
          en:'Britain went to war over the opium trade. Ironclad gunboats forced the Treaty of Nanjing — Hong Kong ceded, ports opened, 21 million silver dollars indemnity. China\'s "century of humiliation" had begun.'} },
  { y:1851, region:'eastasia', sig:'china',
    t:{zh:'太平天国运动', en:'Taiping Heavenly Kingdom'},
    info:{zh:'洪秀全自称耶稣之弟，金田起义，定都天京，建"太平天国"。十四年战事波及十六省，死亡逾两千万——人类 19 世纪伤亡最惨重的内战，也彻底动摇了清廷根基。',
          en:'Hong Xiuquan, claiming to be Jesus\'s brother, ignited a revolt that built the Taiping Heavenly Kingdom in Nanjing. Fourteen years and over 20 million dead — the deadliest civil war of the 19th century.'} },
  { y:1859, region:'europe', sig:'science',
    t:{zh:'达尔文《物种起源》', en:'Darwin\'s On the Origin of Species'},
    info:{zh:'达尔文以"自然选择"解释物种起源，将人类与一切生命置于同一棵进化树。神创世界观就此动摇，生物学、社会思想与神学皆被迫重新定位。',
          en:'Darwin explained life through natural selection, placing humans on a single tree with all other species. The creationist worldview cracked; biology, society and theology had to recast themselves.'} },
  { y:1894, region:'eastasia', sig:'china',
    t:{zh:'甲午战争 · 北洋舰队覆没', en:'First Sino-Japanese War'},
    info:{zh:'清日开战于黄海。号称亚洲第一的北洋水师全军覆没，《马关条约》割让台湾、赔银两亿两。日本由此跃为列强，中国知识界从此走向"救亡图存"的激进追问。',
          en:'Qing and Meiji Japan clashed at sea. The vaunted Beiyang Fleet was annihilated; Taiwan was ceded under the Treaty of Shimonoseki. Japan joined the great powers; Chinese intellectuals turned toward radical reform.'} },
  { y:1911, region:'eastasia', sig:'china',
    t:{zh:'辛亥革命 · 帝制终结', en:'Xinhai Revolution ends the empire'},
    info:{zh:'武昌起义打响，各省独立，清帝退位。两千一百三十二年的皇帝制度在一夜之间结束。孙中山就任中华民国临时大总统——亚洲第一个共和国诞生，前路却仍是漫长的乱世。',
          en:'The Wuchang uprising spread, provinces seceded, the Qing emperor abdicated. Two thousand years of imperial rule ended in months. Sun Yat-sen took office as Asia\'s first republican president.'} },
  { y:1914, region:'europe', sig:'war',
    t:{zh:'第一次世界大战', en:'World War I begins'},
    info:{zh:'萨拉热窝一声枪响，把欧洲两大同盟体系拖入四年绞肉机。坦克、毒气、机关枪——19 世纪的浪漫主义在凡尔登的泥泞中死去，旧帝国与旧秩序一并埋葬。',
          en:'A pistol shot in Sarajevo dragged Europe\'s alliances into a four-year slaughter. Tanks, gas and machine guns buried 19th-century romanticism in the mud of Verdun — and four old empires with it.'} },
  { y:1917, region:'europe', sig:'revolution',
    t:{zh:'十月革命 · 苏联诞生', en:'October Revolution — Soviet Union born'},
    info:{zh:'列宁率布尔什维克在彼得格勒夺权，宣告人类第一个社会主义国家诞生。它将与资本主义阵营对抗 74 年，并深刻影响中国、古巴、越南等无数国家的现代命运。',
          en:'Lenin\'s Bolsheviks seized power in Petrograd, founding the world\'s first socialist state. For 74 years it would face the capitalist West — and shape the modern fates of China, Cuba and Vietnam.'} },
  { y:1937, region:'eastasia', sig:'china',
    t:{zh:'卢沟桥事变 · 全面抗战爆发', en:'Marco Polo Bridge — total war with Japan'},
    info:{zh:'7 月 7 日卢沟桥的枪声，把中国拖入八年全面战争。三千五百万军民伤亡，国共暂搁分歧并肩作战。这场战争既是民族屈辱的极点，也是民族意识的熔炉。',
          en:'On July 7, gunfire at Marco Polo Bridge plunged China into eight years of total war. 35 million casualties, KMT and CCP fighting side by side — both China\'s lowest hour and the forge of its national consciousness.'} },
  { y:1945, region:'global', sig:'war',
    t:{zh:'二战终结 · 核时代开启', en:'WWII ends · Atomic age begins'},
    info:{zh:'广岛、长崎两声爆炸结束六年世界大战，也宣告人类进入可以自我毁灭的新时代。联合国在废墟上成立，美苏两极取代旧欧洲，冷战的帷幕缓缓拉开。',
          en:'Two flashes over Hiroshima and Nagasaki ended six years of war and ushered humanity into an era capable of its own annihilation. The UN rose from the rubble; the Cold War curtain began to fall.'} },
  { y:1947, region:'southasia', sig:'independence',
    t:{zh:'印度独立 · 印巴分治', en:'India independent — Partition'},
    info:{zh:'英属印度脱离大英帝国，分裂为印度与巴基斯坦两国。一千四百万人在仓促划定的边界两侧迁徙，至少一百万人死于教派屠杀——这是 20 世纪规模最大的人口流动。',
          en:'British India broke free — and split into India and Pakistan. 14 million crossed hastily drawn borders; at least a million died in communal massacres. The largest forced migration of the 20th century.'} },
  { y:1949, region:'eastasia', sig:'china',
    t:{zh:'中华人民共和国成立', en:'People\'s Republic of China founded'},
    info:{zh:'10 月 1 日，毛泽东在天安门城楼宣告"中国人民从此站起来了"。三年内战结束，国民政府退守台湾。一个农业古国开始用最激烈的方式追赶 20 世纪。',
          en:'On October 1, Mao Zedong proclaimed from Tiananmen that "the Chinese people have stood up". Civil war ended; the KMT retreated to Taiwan. An agrarian civilization began chasing the 20th century at full speed.'} },
  { y:1969, region:'americas', sig:'tech',
    t:{zh:'阿波罗 11 号登月', en:'Apollo 11 Moon landing'},
    info:{zh:'阿姆斯特朗在静海留下"人类的一大步"。冷战的太空竞赛在此达到顶点，也第一次让全人类同时仰望同一片屏幕——地球，是我们共同的小蓝点。',
          en:'Armstrong\'s "giant leap" landed in the Sea of Tranquility. The Space Race peaked, and humanity watched, as one, a single screen — and saw Earth as a shared pale blue dot.'} },
  { y:1978, region:'eastasia', sig:'china',
    t:{zh:'改革开放 · 中国转向市场', en:'Deng\'s Reform and Opening Up'},
    info:{zh:'十一届三中全会确立"以经济建设为中心"。深圳从渔村变成特区，"摸着石头过河"成为口号。此后四十年，中国 GDP 增长百倍，八亿人脱贫，世界经济版图被重画。',
          en:'The Third Plenum put economic development first. Shenzhen turned from fishing village to special zone. Over the next 40 years China\'s GDP grew 100-fold, lifting 800 million from poverty and redrawing the world map.'} },
  { y:1989, region:'europe', sig:'collapse',
    t:{zh:'柏林墙倒塌', en:'Fall of the Berlin Wall'},
    info:{zh:'东德民众用锤子凿碎了 28 年的水泥墙。两年内，苏联与华约相继瓦解。福山宣称"历史的终结"——然而人们很快会发现，故事远未结束。',
          en:'East Germans hammered down 28 years of concrete. Within two years, the USSR and Warsaw Pact collapsed. Fukuyama declared "the end of history" — only for history to keep going.'} },
  { y:1991, region:'global', sig:'tech',
    t:{zh:'万维网公开 · 互联网时代', en:'World Wide Web goes public'},
    info:{zh:'伯纳斯-李在 CERN 写下第一个网页，并把它免费交给世界。十年内，电子邮件、搜索引擎与电商重塑工作；二十年内，社交网络重塑日常生活。',
          en:'Tim Berners-Lee published the first webpage at CERN and gave it to the world for free. Within a decade, email, search and e-commerce reshaped work; within two, social media reshaped everyday life.'} },
  { y:1997, region:'eastasia', sig:'china',
    t:{zh:'香港回归', en:'Hong Kong returns to China'},
    info:{zh:'7 月 1 日零时，米字旗降下，五星红旗升起。鸦片战争留下的伤口在 156 年后被合上，"一国两制"在世界城市的天际线下开始它最复杂的一场试验。',
          en:'At midnight on July 1, the Union Jack came down and the Five-Star Red Flag rose. A wound left by the Opium War closed after 156 years; "One Country, Two Systems" began its most complex experiment.'} },
  { y:2001, region:'global', sig:'war',
    t:{zh:'9·11 事件 · 反恐战争', en:'9/11 — War on Terror'},
    info:{zh:'两架客机撞向纽约世贸中心。冷战后短暂的"历史终结"幻觉被击碎，美国发动阿富汗与伊拉克战争，全球安全、监控与移民秩序被重新书写。',
          en:'Two airliners struck the World Trade Center. The post-Cold War "end of history" mood shattered. The US launched the wars in Afghanistan and Iraq, rewriting global security, surveillance and migration.'} },
  { y:2007, region:'americas', sig:'tech',
    t:{zh:'iPhone · 移动互联网时代', en:'iPhone — mobile era'},
    info:{zh:'乔布斯把电脑、电话和互联网装进口袋。十年内，全球七十亿人中有近一半每天看着发光的小屏度过若干小时——人类的注意力史，被重写一次。',
          en:'Jobs put computer, phone and internet in your pocket. Within a decade nearly half of humanity spent hours daily staring at a glowing rectangle — the history of attention itself was rewritten.'} },
  { y:2020, region:'global', sig:'plague',
    t:{zh:'COVID-19 全球大流行', en:'COVID-19 pandemic'},
    info:{zh:'新冠病毒在数月内席卷全球。封城、远程办公、疫苗竞赛、供应链断裂——一场瘟疫加速了过去十年所有未完成的趋势:远程化、数字化、地缘对抗。',
          en:'A new coronavirus swept the planet within months. Lockdowns, remote work, vaccine sprints, broken supply chains — a pandemic accelerated every unfinished trend of the prior decade.'} },
  { y:2022, region:'global', sig:'tech',
    t:{zh:'ChatGPT · 大模型时代', en:'ChatGPT — Large-Model era'},
    info:{zh:'11 月 30 日，OpenAI 上线 ChatGPT，五天破百万用户。生成式 AI 从实验室跃入日常，软件、教育、创作的边界被一夜重写——下一段历史，正在被它和我们共同书写。',
          en:'On November 30, OpenAI launched ChatGPT — a million users in five days. Generative AI leapt from lab to daily life, redrawing the borders of software, education and creativity. The next chapter is being written with it.'} },
];
